import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class SecureXSS {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS attack!')</script>";
        String sanitizedInput = Encode.forHtml(userInput);

        // Properly handling user input by encoding it before outputting to the webpage
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<head><title>Secure XSS</title></head>");
        out.println("<body>");
        out.println("<h1>User Input: " + sanitizedInput + "</h1>"); // XSS vulnerability fixed
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
